import{_ as a,o as t,c as s,a0 as r}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Edit a User & Reset Their Password","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/edit-user.md","filePath":"how-to/edit-user.md"}'),o={name:"how-to/edit-user.md"};function i(n,e,l,h,d,c){return t(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="edit-a-user-reset-their-password" tabindex="-1">Edit a User &amp; Reset Their Password <a class="header-anchor" href="#edit-a-user-reset-their-password" aria-label="Permalink to &quot;Edit a User &amp; Reset Their Password&quot;">​</a></h1><p>After a user exists, you manage them from the <strong>Users</strong> list and their <strong>Edit</strong> page. This is where you update identity details, suspend or reactivate access, and decide whether they must change their password next time they sign in.</p><h2 id="open-the-user" tabindex="-1">Open the user <a class="header-anchor" href="#open-the-user" aria-label="Permalink to &quot;Open the user&quot;">​</a></h2><ol><li>Open <strong>Admin</strong>.</li><li>Find the user in <strong>Users</strong>.</li><li>Select <strong>Edit</strong>.</li></ol><p>The user page is split into two main parts:</p><ul><li><strong>User Profile</strong> for account details.</li><li><strong>Current Assignments</strong> and <strong>Add Assignment</strong> for role and scope changes.</li></ul><h2 id="what-you-can-change" tabindex="-1">What you can change <a class="header-anchor" href="#what-you-can-change" aria-label="Permalink to &quot;What you can change&quot;">​</a></h2><p>On <strong>User Profile</strong>, you can update:</p><ul><li><strong>Username</strong></li><li><strong>Display name</strong></li><li><strong>Email</strong></li><li><strong>Active</strong></li><li><strong>Force password change</strong></li></ul><p>If you are a <code>Supreme Admin</code>, you can also change the user&#39;s global role between regular user access and <code>Supreme Admin</code>.</p><h2 id="when-to-use-force-password-change" tabindex="-1">When to use &quot;Force password change&quot; <a class="header-anchor" href="#when-to-use-force-password-change" aria-label="Permalink to &quot;When to use &quot;Force password change&quot;&quot;">​</a></h2><p>Turn on <strong>Force password change</strong> when you want the user to pick a fresh password the next time they log in. This is helpful after handoffs, shared setup work, or any situation where you no longer want the current password to remain in use.</p><h2 id="reset-a-password-by-email" tabindex="-1">Reset a password by email <a class="header-anchor" href="#reset-a-password-by-email" aria-label="Permalink to &quot;Reset a password by email&quot;">​</a></h2><p>The password reset action starts from the <strong>Users</strong> list, not from the profile form.</p><ol><li>Go back to <strong>Admin</strong>.</li><li>In the user row, select <strong>Reset</strong>.</li><li>Confirm the email action.</li></ol><p>What happens:</p><ul><li>The system creates a one-time temporary password.</li><li>That password is emailed to the user&#39;s saved email address.</li><li>The user is forced to change it at next login.</li></ul><p>If the user does not have an email address saved, the reset action is not available.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Use profile editing for normal account changes.</li><li>Use the email reset flow when you want a clean, private password handoff.</li><li>Use role assignments instead of rewriting the account when the real change is scope or responsibility.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-user.html">Create a User</a></li><li><a href="./assign-roles.html">Assign or Remove Roles</a></li><li><a href="./handle-password-requests.html">Handle Password Reset Requests</a></li><li><a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a></li></ul>',22)])])}const g=a(o,[["render",i]]);export{p as __pageData,g as default};
